            val filtered = _palettes.value.mapNotNull { palette ->
                val nameKey = palette.name?.replace(" ", "")?.lowercase() ?: return@mapNotNull null
                val label = PALETTE_LABELS[nameKey]
                if (label != null) palette to label else null
