        val reflectedTemperature: ThermalValue = ThermalValue(20.0, TemperatureUnit.CELSIUS),
        val atmosphericTemperature: ThermalValue = ThermalValue(20.0, TemperatureUnit.CELSIUS),
        val relativeHumidity: Double = 50.0
