    fun onSnapshotSaved(path: String) {
        _recentThermograms.value = buildList {
            add(path)
            addAll(_recentThermograms.value.filterNot { it == path })
        }.filter { File(it).exists() }.take(20)
        persistRecentThermograms(_recentThermograms.value)
